type WeaponValue   = "can" | "cannot" | "weak";
type SkillValue    = "can" | "cannot";
type SkillAccessKey = "attack" | "attackMagic" | "recovery";
type SkillAccessMap = Partial<Record<SkillAccessKey, SkillValue>> & { casting?: SkillValue };
type JobStatEntry  = { base: number; inc: number; levels?: Record<string,number> };
type JobRankData   = { stats: Record<string,JobStatEntry> };
type Job = {
  generation: 1 | 2;
  type?: "combat" | "non-combat";
  icon?: string;
  ranks: Record<string,JobRankData>;
  shield?: "can" | "cannot";
  weaponEquip?: Partial<Record<string,WeaponValue>>;
  skillAccess?: SkillAccessMap;
  skills: string[];
  shops?: string[];
  notes?: string;
};
type SharedPair = { id: string; jobA: string; jobB: string; children: string[]; affinity?: string };

type SharedData = {
  jobs: Record<string,Job>;
  statIcons: Record<string,string>;
  weaponCategories?: string[];
  pairs?: SharedPair[];
};

const SKILL_ACCESS_LABELS: Record<SkillAccessKey, string> = {
  attack: "Attack Skills",
  attackMagic: "Casting Skills",
  recovery: "Healing Skills",
};

