const RANKED_SKILL_ACCESS_FALLBACKS: Record<string, Partial<Record<string, SkillAccessMap>>> = {
  Monarch: {
    D: { attack: "can", attackMagic: "can", recovery: "can" },
    C: { attack: "cannot", attackMagic: "can", recovery: "can" },
    B: { attack: "cannot", attackMagic: "cannot", recovery: "can" },
    A: { attack: "cannot", attackMagic: "cannot", recovery: "cannot" },
    S: { attack: "can", attackMagic: "cannot", recovery: "cannot" },
  },
};

function getResolvedWeaponAccess(jobName: string, job: Job, weaponClass: string): WeaponValue | undefined {
  return job.weaponEquip?.[weaponClass] ?? JOB_WEAPON_ACCESS_FALLBACKS[jobName]?.[weaponClass];
}

function getResolvedShieldAccess(jobName: string, job: Job): WeaponValue | undefined {
  return (
    job.weaponEquip?.Shield
    ?? (job.shield === "can" ? "can" : job.shield === "cannot" ? "cannot" : undefined)
    ?? JOB_SHIELD_FALLBACKS[jobName]
  );
}

function getResolvedSkillAccess(jobName: string, job: Job, selectedRank?: string): SkillAccessMap {
  const saved = job.skillAccess ?? {};
  const fallback = SHEET_SKILL_ACCESS_FALLBACKS[jobName] ?? {};
  const rankedFallback = selectedRank ? (RANKED_SKILL_ACCESS_FALLBACKS[jobName]?.[selectedRank] ?? {}) : {};
  return {
    attack: saved.attack ?? rankedFallback.attack ?? fallback.attack,
    attackMagic: saved.attackMagic ?? saved.casting ?? rankedFallback.attackMagic ?? fallback.attackMagic,
    recovery: saved.recovery ?? rankedFallback.recovery ?? fallback.recovery,
  };
}

function statAtLevel(entry: JobStatEntry, level: number): number {
  const ov = entry.levels?.[String(level)];
  if (ov !== undefined) return ov;
  return entry.base + (level - 1) * entry.inc;
}

function getResolvedShops(jobName: string, shops?: string[]): string[] {
  if (shops && shops.length > 0) return shops;
  return KNOWN_JOB_SHOPS[jobName] ?? [];
}

