export default function JobsPage() {
  const { name: jobParam } = useParams<{ name?: string }>();
  const [, navigate]       = useLocation();
  const { dark, setDark }  = useDarkMode();
  const { name: userName, save: saveUserName } = useUserName();
  const [promptName, setPromptName] = useState(false);
  const [pendingFn,  setPendingFn]  = useState<(() => void) | null>(null);
  const [pageNote,   setPageNote]   = useState(() => localStorage.getItem("ka_note_jobs") ?? "");
  const [showNote,   setShowNote]   = useState(false);
  const qc = useQueryClient();
  const { data, isLoading, refetch } = useSharedData();

  const jobs:             Record<string,Job>    = data?.jobs ?? {};
  const statIcons:        Record<string,string> = data?.statIcons ?? {};
  const weaponCategories: string[]              = data?.weaponCategories ?? [];
  const pairs:            SharedPair[]          = data?.pairs ?? [];

  const withName = useCallback((fn: () => void) => {
    if (!userName) { setPendingFn(() => fn); setPromptName(true); }
    else fn();
  }, [userName]);

  const onNameSaved = (n: string) => {
    saveUserName(n); setPromptName(false);
    if (pendingFn) { pendingFn(); setPendingFn(null); }
  };

  const handleSaveJobs = useCallback((updated: Record<string,Job>, desc: string) => {
    withName(() => {
      qc.setQueryData(["ka-shared"], (old: SharedData|undefined) => old ? { ...old, jobs: updated } : old);
      persistJobs(updated, userName, desc).then(() => qc.invalidateQueries({ queryKey: ["ka-shared"] }));
    });
  }, [qc, userName, withName]);

  const handleSavePairs = useCallback((updated: SharedPair[]) => {
    withName(() => {
      qc.setQueryData(["ka-shared"], (old: SharedData|undefined) => old ? { ...old, pairs: updated } : old);
      persistPairs(updated, userName).then(() => qc.invalidateQueries({ queryKey: ["ka-shared"] }));
    });
  }, [qc, userName, withName]);

  const selectedJob = jobParam ? decodeURIComponent(jobParam) : null;

  useEffect(() => {
    if (typeof window !== "undefined") {
      window.scrollTo({ top: 0, left: 0, behavior: "auto" });
    }
  }, [selectedJob]);

  return (
    <div className="min-h-screen bg-background transition-colors">
      {promptName && <NamePrompt onSave={onNameSaved} />}

      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            {!selectedJob && (
              <Link href="/">
                <button className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground transition-colors">
                  <ArrowLeft className="w-4 h-4" />Home
                </button>
              </Link>
            )}
            {!selectedJob && (
              <>
                <span className="text-muted-foreground/30">/</span>
                <h1 className="text-xl font-bold text-foreground flex items-center gap-2">
                  <Briefcase className="w-5 h-5 text-sky-500" />Job Database
                </h1>
              </>
            )}
          </div>
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon" onClick={() => setShowNote((v) => !v)} className="h-8 w-8 text-muted-foreground" title="Personal notes (private, stored on this device)">
              <Info className="w-3.5 h-3.5" />
            </Button>
            <Button variant="ghost" size="icon" onClick={() => {
              if (confirm("Reset your private data for Jobs (favourites, rank selections)? Community data is not affected.")) {
                localStorage.removeItem("ka_fav_jobs");
                localStorage.removeItem("ka_rank_slots");
                window.location.reload();
              }
            }} className="h-8 w-8 text-muted-foreground" title="Reset private data (favourites, rank selections)">
              <RotateCcw className="w-3.5 h-3.5" />
            </Button>
            <Button variant="ghost" size="sm" onClick={() => refetch()} className="h-8 gap-1.5 text-muted-foreground">
              {isLoading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <RefreshCw className="w-3.5 h-3.5" />}
            </Button>
            <Button variant="outline" size="icon" onClick={() => setDark((d) => !d)} className="h-8 w-8">
              {dark ? <Sun className="w-3.5 h-3.5" /> : <Moon className="w-3.5 h-3.5" />}
            </Button>
          </div>
        </div>

        {showNote && (
          <div className="mb-4">
            <textarea
              value={pageNote}
              onChange={(e) => setPageNote(e.target.value)}
              onBlur={() => localStorage.setItem("ka_note_jobs", pageNote)}
              placeholder="Personal notes for this pageÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¦ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¦ (only visible to you, saved on this device)"
              className="w-full h-20 text-sm rounded-md border border-input bg-muted/20 px-3 py-2 resize-none focus:outline-none focus:ring-1 focus:ring-ring placeholder:text-muted-foreground/40"
            />
          </div>
        )}

        {/* Content */}
        {isLoading ? (
          <div className="flex items-center justify-center py-24"><Loader2 className="w-6 h-6 animate-spin text-muted-foreground" /></div>
        ) : selectedJob && jobs[selectedJob] ? (
          <JobDetailPage
            jobName={selectedJob}
            jobs={jobs}
            statIcons={statIcons}
            weaponCategories={weaponCategories}
            pairs={pairs}
            onSave={handleSaveJobs}
            onSavePairs={handleSavePairs}
            userName={userName}
          />
        ) : selectedJob ? (
          <div className="text-center py-16 text-sm text-muted-foreground">
            Job "{selectedJob}" not found.{" "}
            <button onClick={() => navigate("/jobs")} className="text-primary hover:underline">Back to list</button>
          </div>
        ) : (
          <JobsTable
            jobs={jobs}
            statIcons={statIcons}
            userName={userName}
            onSaveJobs={handleSaveJobs}
          />
        )}
      </div>
    </div>
  );
}


